sql.if:
and stk.department_id in (
    select distinct x.did from (
        select cast(upd.dept_id as unsigned) as did
        from sb_user_permission_dept upd
        where upd.user_id = #{params.scopeDeptUserId}
          and ifnull(upd.del_flag, '0') = '0'

          and upd.customer_id = #{params.scopeDeptCustomerId}

        union
        select ud.department_id as did
        from sys_user_department ud
        where ud.user_id = #{params.scopeDeptUserId}
          and (ud.status = 0 or ud.status = '0' or ud.status is null)
    ) x
    where x.did is not null
)

mapper.select:


where stk.del_flag != 1
and stk.tenant_id = #{scopedTenantId}

 and stk.bill_no like concat('%', #{billNo}, '%')
 and stk.ref_bill_no = #{refBillNo}
 and stk.suppler_id = #{supplerId}
 and stk.warehouse_id = #{warehouseId}
 and stk.department_id = #{departmentId}
 and stk.bill_status = #{billStatus}
 and stk.user_id = #{userId}

    and stk.bill_type = #{billType}

     and stk.bill_no not like 'JS%'




         and stk.bill_date >= #{beginDate}
         and stk.bill_date <= #{endDate}


         and stk.audit_date >= #{beginDate}
         and stk.audit_date <= #{endDate}


 and stk.audit_date >= #{auditBeginDate}
 and DATE(stk.audit_date) <= DATE(#{auditEndDate})
 and stk.receipt_confirm_status = #{receiptConfirmStatus}
 and exists (select 1 from stk_io_bill_entry e inner join fd_material m on e.material_id = m.id where e.paren_id = stk.id and (e.del_flag is null or e.del_flag != 1) and (m.name like concat('%', #{materialName}, '%') or m.code like concat('%', #{materialName}, '%')))

    and  = #{params.docRefStatus}



    and (
        select count(distinct nullif(trim(e.suppler_id), ''))
        from stk_io_bill_entry e
        where e.paren_id = stk.id and (e.del_flag is null or e.del_flag != 1)
          and e.suppler_id is not null and trim(e.suppler_id) != ''
    ) <= 1

order by
    case when stk.bill_status = 2 then 1 else 0 end asc,
    case when stk.bill_status = 2 then stk.audit_date else null end desc,
    case when stk.bill_status = 2 then null else stk.create_time end desc,
    stk.id desc


select stk.id as billId,
       stk.bill_no as billNo,
       ifnull(d.name, '') as departmentName,
       ifnull(m.name, '') as materialName,
       ifnull(m.speci, '') as speci,
       ifnull(m.model, '') as model,
       ifnull(u.unit_name, '') as unitName,
       b.qty as qty,
       b.unit_price as unitPrice,
       b.amt as amt,
       case when b.batch_number is not null and trim(b.batch_number) != '' then trim(b.batch_number) else ifnull(b.batch_no, '') end as batchPh,
       b.end_time as endTime
from stk_io_bill stk
inner join stk_io_bill_entry b on b.paren_id = stk.id and (b.del_flag is null or b.del_flag != 1)
left join fd_department d on stk.department_id = d.id
left join fd_material m on b.material_id = m.id
left join fd_unit u on m.unit_id = u.unit_id
