  and e.delivery_line_sign = #{lineSign}

  and b.id != #{excludeBillId}

select t.statDate, t.supplierName, t.materialCategoryName, t.amount from ( select DATE_FORMAT(stk.audit_date, '%Y-%m-%d') as statDate, IFNULL(MAX(COALESCE(s_line.name, s_bill.name)), '未指定供应商') as supplierName, IFNULL(NULLIF(TRIM(MAX(mc.material_category_name)), ''), '未识别分类') as materialCategoryName, ROUND(SUM(), 2) as amount from stk_io_bill stk inner join stk_io_bill_entry b on b.paren_id = stk.id and (b.del_flag is null or b.del_flag != 1) inner join fd_material m on m.id = b.material_id left join fd_material_category mc on mc.material_category_id = m.material_category_id and mc.tenant_id = stk.tenant_id and (mc.del_flag is null or mc.del_flag != 1) left join fd_supplier s_line on s_line.id = (case when b.suppler_id is not null and trim(b.suppler_id) <> '' then cast(trim(b.suppler_id) as unsigned) else null end) left join fd_supplier s_bill on s_bill.id = stk.suppler_id left join fd_department d on d.id = stk.department_id left join fd_warehouse w on w.id = stk.warehouse_id where (stk.del_flag = 0 or stk.del_flag is null) and stk.tenant_id = #{scopedTenantId} and stk.bill_type in (201, 401) and stk.bill_status = 2 and stk.audit_date >= #{beginDate} and stk.audit_date <= #{endDate} and stk.warehouse_id = #{warehouseId} and stk.department_id = #{departmentId} and (case when b.suppler_id is not null and trim(b.suppler_id) <> '' then cast(trim(b.suppler_id) as unsigned) else stk.suppler_id end) = #{supplerId}
and (w.code like concat('%', #{warehouseKeyword}, '%') or w.name like concat('%', #{warehouseKeyword}, '%') or w.referred_name like concat('%', #{warehouseKeyword}, '%'))
and ((s_line.code like concat('%', #{supplierKeyword}, '%') or s_line.name like concat('%', #{supplierKeyword}, '%') or s_line.referred_code like concat('%', #{supplierKeyword}, '%')) or (s_bill.code like concat('%', #{supplierKeyword}, '%') or s_bill.name like concat('%', #{supplierKeyword}, '%') or s_bill.referred_code like concat('%', #{supplierKeyword}, '%')))
and (d.code like concat('%', #{departmentKeyword}, '%') or d.name like concat('%', #{departmentKeyword}, '%') or d.referred_name like concat('%', #{departmentKeyword}, '%'))
group by DATE_FORMAT(stk.audit_date, '%Y-%m-%d'), IFNULL(NULLIF(TRIM(mc.material_category_name), ''), '未识别分类'), (case when b.suppler_id is not null and trim(b.suppler_id) <> '' then cast(trim(b.suppler_id) as unsigned) else stk.suppler_id end) ) t order by t.statDate asc, t.supplierName asc, t.materialCategoryName asc
LIMIT #{params.medicalSummaryOffset}, #{params.medicalSummaryLimit}

select t.statDate, t.departmentName, t.materialCategoryName, t.amount, t.unitName, t.isGzText from ( select DATE_FORMAT(stk.audit_date, '%Y-%m-%d') as statDate, IFNULL(MAX(d.name), '未指定科室') as departmentName, IFNULL(NULLIF(TRIM(MAX(mc.material_category_name)), ''), '未识别分类') as materialCategoryName, ROUND(SUM(), 2) as amount, '其他' as unitName, CASE WHEN MAX(IFNULL(m.is_gz, '2')) = '1' THEN '是' ELSE '否' END as isGzText from stk_io_bill stk inner join stk_io_bill_entry b on b.paren_id = stk.id and (b.del_flag is null or b.del_flag != 1) inner join fd_material m on m.id = b.material_id left join fd_material_category mc on mc.material_category_id = m.material_category_id and mc.tenant_id = stk.tenant_id and (mc.del_flag is null or mc.del_flag != 1) left join fd_department d on d.id = stk.department_id left join fd_warehouse w on w.id = stk.warehouse_id left join fd_supplier s_line on s_line.id = (case when b.suppler_id is not null and trim(b.suppler_id) <> '' then cast(trim(b.suppler_id) as unsigned) else null end) left join fd_supplier s_bill on s_bill.id = stk.suppler_id where (stk.del_flag = 0 or stk.del_flag is null) and stk.tenant_id = #{scopedTenantId} and stk.bill_type in (201, 401) and stk.bill_status = 2 and stk.audit_date >= #{beginDate} and stk.audit_date <= #{endDate} and stk.warehouse_id = #{warehouseId} and stk.department_id = #{departmentId} and (case when b.suppler_id is not null and trim(b.suppler_id) <> '' then cast(trim(b.suppler_id) as unsigned) else stk.suppler_id end) = #{supplerId}
and (w.code like concat('%', #{warehouseKeyword}, '%') or w.name like concat('%', #{warehouseKeyword}, '%') or w.referred_name like concat('%', #{warehouseKeyword}, '%'))
and ((s_line.code like concat('%', #{supplierKeyword}, '%') or s_line.name like concat('%', #{supplierKeyword}, '%') or s_line.referred_code like concat('%', #{supplierKeyword}, '%')) or (s_bill.code like concat('%', #{supplierKeyword}, '%') or s_bill.name like concat('%', #{supplierKeyword}, '%') or s_bill.referred_code like concat('%', #{supplierKeyword}, '%')))
and (d.code like concat('%', #{departmentKeyword}, '%') or d.name like concat('%', #{departmentKeyword}, '%') or d.referred_name like concat('%', #{departmentKeyword}, '%'))
group by DATE_FORMAT(stk.audit_date, '%Y-%m-%d'), IFNULL(NULLIF(TRIM(mc.material_category_name), ''), '未识别分类'), stk.department_id, IFNULL(m.is_gz, '2') ) t order by t.statDate asc, t.departmentName asc, t.materialCategoryName asc
LIMIT #{params.medicalSummaryOffset}, #{params.medicalSummaryLimit}

select stk.warehouse_id as warehouseId, coalesce(sum(case when stk.bill_type in (101, 301) then (case when stk.bill_type = 301 then -IFNULL(b.qty, 0) else IFNULL(b.qty, 0) end) else 0 end), 0) as rthQty, coalesce(sum(case when stk.bill_type in (101, 301) then (case when stk.bill_type = 301 then -(IFNULL(b.qty, 0) * IFNULL(b.unit_price, 0)) else (IFNULL(b.qty, 0) * IFNULL(b.unit_price, 0)) end) else 0 end), 0) as rthAmt, coalesce(sum(case when stk.bill_type in (201, 401) then (case when stk.bill_type = 401 then -IFNULL(b.qty, 0) else IFNULL(b.qty, 0) end) else 0 end), 0) as ctkQty, coalesce(sum(case when stk.bill_type in (201, 401) then (case when stk.bill_type = 401 then -(IFNULL(b.qty, 0) * IFNULL(b.unit_price, 0)) else (IFNULL(b.qty, 0) * IFNULL(b.unit_price, 0)) end) else 0 end), 0) as ctkAmt from stk_io_bill stk left join stk_io_bill_entry b on b.paren_id = stk.id and (b.del_flag is null or b.del_flag != 1) where (stk.del_flag = 0 or stk.del_flag is null) and stk.tenant_id = #{scopedTenantId} and stk.bill_status = 2 and stk.bill_type in (101, 301, 201, 401) and stk.audit_date >= #{beginDate} and stk.audit_date <= #{endDate} and stk.warehouse_id in
#{wid}
group by stk.warehouse_id
